+  const context = contextMatch?.[1]?.trim().replace(/\s+/g, " ") ?? "";
+
+  const quote = text
+    .split(/\n(?:Takeaway|Why it matters):/i)[0]
+    ?.trim()
+    .replace(/\s+/g, " ") ?? "";
+
+  return { quote, context, tags };
+}
+
+function titleCaseFromTag(tag: string): string {
+  return tag
+    .replace(/[_-]+/g, " ")
+    .trim()
+    .split(/\s+/)
+    .map((w) => (w.length > 0 ? w[0]!.toUpperCase() + w.slice(1) : w))
+    .join(" ");
